import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider } from './context/AuthContext';
import ProtectedRoute from './admin/components/ProtectedRoute';


// Admin pages
import AdminLogin from './admin/src/pages/admin/AdminLogin';
import Dashboard from './admin/src/pages/admin/Dashboard';   // ← ADD THIS
import AddGem from './admin/src/pages/admin/AddGem';
import EditGem from './admin/src/pages/admin/EditGem';


export default function App() {
  return (
    <AuthProvider>
      <Router>
        <Routes>


          {/* Admin auth */}
          <Route path="/admin/login" element={<AdminLogin />} />

          {/* ← ADD THESE TWO */}
          <Route path="/admin" element={<Navigate to="/admin/dashboard" replace />} />
          <Route path="/admin/dashboard" element={
            <ProtectedRoute><Dashboard /></ProtectedRoute>
          } />

          <Route path="/admin/add-gem" element={
            <ProtectedRoute><AddGem /></ProtectedRoute>
          } />
          <Route path="/admin/edit-gem/:id" element={
            <ProtectedRoute><EditGem /></ProtectedRoute>
          } />

          {/* Catch-all */}
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
}
